var INVASIVE = [
{id:"iv",name:"i.v.-Zugang",indikationen:["Infusion erforderlich (medizinische Indikation)","(Zu erwartende) Medikamentengabe i.v. erforderlich"],kontra:["Infektion an der Punktionsstelle","Dialyse-Shunt / Z.n. axillärer Lymphknotenentfernung","Paretische Extremität","Verletzte oder (vor-)geschädigte Extremität"],durchfuehrung:"Geeignete Punktionsstelle suchen (von peripher nach zentral), Ellenbeuge möglichst vermeiden. Desinfektion → Venenstau → erneute Hautdesinfektion → Punktion → Blut in Kammer des Mandrins → Kunststoffkanüle vorschieben → Venenstau aufheben → Mandrin entfernen und sicher entsorgen → Infusion anschließen / Probeinjektion → sichere Fixierung.",alternativen:["Intranasal, buccal, sublingual, rektal, oral","Intramuskulär","Intraossärer Zugang","Verzicht bis Eintreffen NA"],erfolg:"Ggf. Rücklaufprobe, frei fließende Infusion ohne Paravasat, ggf. Probeinjektion NaCl/Aqua, keine Schwellung proximal der Punktionsstelle",gauge:"14G: 2,2mm/343ml/min · 16G: 1,7mm/196ml/min · 18G: 1,3mm/96ml/min · 20G: 1,1mm/61ml/min · 22G: 0,9mm/36ml/min"},
{id:"io",name:"i.o.-Zugang (EZ-IO/COOK/BIG)",indikationen:["Herz-Kreislauf-Stillstand","Lebensbedrohliche Situation mit zwingender Indikation für parenteralen Zugang UND Unmöglichkeit eines peripheren i.v.-Zugangs"],kontra:["Fraktur der entsprechenden Tibia","Vorheriger Punktionsversuch am selben Knochen","Infektion, Endoprothese oder Implantat an Punktionsstelle","Massive Weichteilschäden an Punktionsstelle"],durchfuehrung:"Punktionsort: proximale Tibia medial der Tuberositas tibiae. Geeignete Nadel wählen → Desinfektion, ggf. rasieren → Verlängerungsschlauch + Dreiwegehahn mit kristalloider Lösung füllen → Durchstechen der Haut senkrecht zur Knochenoberfläche → Einbohren bis Widerstandsverlust → Fixieren, Trokar entfernen → Aspiration von Blut/Knochenmark → Keine Lidocaingabe durch NotSan → Spülen mit ca. 10 ml kristalloider Lösung → Infusion anschließen → Nadel sicher fixieren.",alternativen:["Applikation i.m., nasal, buccal oder rectal (bei erhaltenem Kreislauf)","Verzicht bis Eintreffen NA"],erfolg:"Sicher platzierte, fest sitzende Nadel, keine Schwellung, Aspiration von Blut/Knochenmark, leichtgängiges Injizieren, gewünschte pharmakologische Wirkung"},
{id:"ega",name:"Extraglottischer Atemweg (Übersicht)",indikationen:["Herz-Kreislauf-Stillstand","Ateminsuffizienz mit Bewusstlosigkeit und fehlenden Schutzreflexen"],kontra:["Erhaltene Schutzreflexe","Komplette Verlegung der oberen Atemwege"],durchfuehrung:"Durchführung gemäß spezifischer SAA: LTS-D (Larynxtubus), Larynxmaske 2. Generation oder i-gel. Lagekontrolle: Kapnometrie/Kapnographie + SpO₂.",alternativen:["Beutel-Masken-Beatmung, ggf. mit Guedel-/Wendl-Tubus","Anderes extraglottisches Atemwegssicherungsverfahren"],erfolg:"Sichtbare atemzugsynchrone Thoraxbewegungen, Kapnographie-Signal, Auskultation der Lungen, keine/geringe Atemnebengeräusche im Rachen",anmerkung:"LTS-D für Neugeborene, Säuglinge und Kleinkinder NICHT empfohlen"},
{id:"ega_ltsd",name:"EGA – LTS-D (Larynxtubus)",indikationen:["Herz-Kreislauf-Stillstand","Ateminsuffizienz mit Bewusstlosigkeit und fehlenden Schutzreflexen"],kontra:["Erhaltene Schutzreflexe","Komplette Verlegung der oberen Atemwege","Nicht empfohlen für Neugeborene, Säuglinge und Kleinkinder"],durchfuehrung:"Richtige Tubusgröße wählen → Ventilöffner entfernen, Cuffs prüfen → Cuffs entlüften, ggf. gleitfähig machen → Kopf in Neutralposition → Mund weit öffnen, ggf. FK/Erbrochenes entfernen → Kinn anheben → Tubus mittig am harten Gaumen entlang einführen → Zunge darf nicht zurückfallen (ggf. Finger als Schienung) → Vorschieben bis oberste Zahnmarkierung oder Widerstand → Cuffs blocken (farbcodierte Spritze), Cuffdruck max. 60 cmH₂O → Beatmungsbeutel anschließen → Magensonde in Drainagekanal einführen (max. Gr. 18 Fr) → Lagekontrolle → Fixierung. Beatmungsdruck < 25 mbar.",alternativen:["Larynxmaske 2. Gen.","i-gel","Beutel-Masken-Beatmung"],erfolg:"Atemzugsynchrone Thoraxbewegungen, Kapnographie, Auskultation, keine/geringe Rachennebengeräusche. Magensonde nicht vorschiebbar = V.a. Fehllage!",gegenmassnahmen:"Einführtiefe prüfen (Zahnmarkierung) → ggf. innerhalb Markierungen zurückziehen → Neuplatzierung → Größe wechseln → Entfernen + BMV → ETI als Ultima ratio (wenn beherrscht/durch NA)"},
{id:"ega_lma",name:"EGA – Larynxmaske 2. Gen.",indikationen:["Herz-Kreislauf-Stillstand","Ateminsuffizienz mit Bewusstlosigkeit und fehlenden Schutzreflexen"],kontra:["Erhaltene Schutzreflexe","Komplette Verlegung der oberen Atemwege"],durchfuehrung:"Größtmögliche Maskengröße wählen → Cuff prüfen → Cuff faltenfrei entlüften, Spitze gleitfähig machen → Kopf in Neutralposition (oder leichte Schnüffelposition) → Mund weit öffnen → Maske mittig am harten Gaumen entlang einführen, Gaumenwölbung folgen → Vorschieben bis deutlicher Widerstand → Lage verifizieren → Cuff blocken (max. Volumen nicht überschreiten!), Cuffdruck max. 60 cmH₂O → Beatmungsbeutel anschließen → Magensonde (OG-Tubus) in Drainagesystem → Lagekontrolle → Fixierung. Beatmungsdruck < 25 mbar.",alternativen:["LTS-D","i-gel","Beutel-Masken-Beatmung"],erfolg:"Atemzugsynchrone Thoraxbewegungen, Kapnographie, Auskultation, keine Rachennebengeräusche. Bubble-Test, Suprasternal-Notch-Test. Magensonde problemlos einführbar. LMA Supreme: Fixierlasche zur Oberlippe > 2,5 cm = zu groß, < 1 cm = zu klein.",gegenmassnahmen:"Lagekorrektur/Neuplatzierung → andere Größe → Entfernen + BMV → anderes EGA → ETI als Ultima ratio"},
{id:"ega_igel",name:"EGA – i-gel",indikationen:["Herz-Kreislauf-Stillstand","Ateminsuffizienz mit Bewusstlosigkeit und fehlenden Schutzreflexen"],kontra:["Erhaltene Schutzreflexe","Komplette Verlegung der oberen Atemwege"],durchfuehrung:"Richtige Größe wählen → Sicht-/Funktionskontrolle → Wasserbasiertes Gleitmittel → Kopf leicht überstrecken, Kinn herunterdrücken → Ggf. FK/Erbrochenes entfernen → KEINE Finger in Mund des Patienten → Mit kontinuierlichem, sanftem Druck am harten Gaumen entlang einführen, ggf. 'tiefe Rotation' → Bis Widerstand spürbar → Beatmen → Lagekontrolle → Ggf. Korrektur mit Esmarch-Handgriff → Fixierung mit Pflasterstreifen. Beatmungsdruck ≤ 40 mbar. Magensonde über gastrischen Absaugkanal einführen.",alternativen:["LTS-D","Larynxmaske 2. Gen.","Beutel-Masken-Beatmung"],erfolg:"Atemzugsynchrone Thoraxbewegungen, Kapnographie, Auskultation, keine Rachennebengeräusche. Schneidezähne ruhen auf Beißkeil-Markierung.",gegenmassnahmen:"Einführtiefe prüfen → Lagekorrektur/Neuplatzierung → Größe wechseln (Cave: i-gel-Cuff erscheint kleiner als bei traditionellem EGA!) → Entfernen + BMV → anderes EGA → ETI als Ultima ratio"},
{id:"laryngoskopie",name:"Laryngoskopie",indikationen:["Bolus-Suche und -Entfernung bei (sub-)totaler Atemwegsverlegung / Bolusgeschehen","Kreislaufstillstand unklarer Ursache"],kontra:["Gegenwehr aufgrund von Schutzreflexen (Gefahr Erbrechen/Laryngospasmus)"],durchfuehrung:"Macintosh-Spatel oder Macintosh-ähnlich, bevorzugt Videolaryngoskopie. Beatmungsmöglichkeit + Absaugung bereithalten → Korrekte Lagerung (cave HWS) → Mund öffnen, Rachenraum inspizieren → Laryngoskop vom rechten Mundwinkel einführen, Zahnkontakt vermeiden → Vorschieben unter Sicht, Zunge nach links verlagern → Kehldeckel sichtbar → Zug in Achse des Griffs → Inspektion Hypopharynx/Larynx → FK mit Magillzange fassen und entfernen → Bei CPR + kein FK + Stimmritze erkennbar: ein ETI-Versuch → Niemals blind vorschieben/manipulieren!",alternativen:["Manuelle Entfernung sichtbarer FK","Magillzange ohne Laryngoskop","Absaugung mit großlumigem Katheter (Yankauer)","Rückenschläge, Heimlich-Manöver"],erfolg:"Entfernter FK, verbesserte Oxygenierung, verbesserte Atemmechanik, ggf. etCO₂-Nachweis, Rückbildung Stridor",gegenmassnahmen:"Prüfung korrekte Lagerung (Schnüffelposition) → Absaugen von Sekreten/Blut"},
{id:"thorax",name:"Thoraxentlastungspunktion",indikationen:["Spannungspneumothorax mit rasch zunehmender hämodynamischer und respiratorischer Instabilität"],kontra:["Bei korrekter Indikation und korrektem Punktionsort: keine"],durchfuehrung:"Punktionsstelle: 2. ICR Medioclavicularlinie (Monaldi) ODER 4. ICR vordere Axillarlinie (Bülau). Kanülenlänge > 8 cm, möglichst großlumig → Hautdesinfektion → Halb mit NaCl/Aqua gefüllte Spritze auf Kanüle → Punktion am Oberrand der Rippe senkrecht zur Thoraxwand → Monaldi: Cave A. thoracica interna bei zu medialem Punktionsort → Bülau: Cave Organverletzungen bei zu caudalem Ort → Aspiration von Luft = Pleuraspalt erreicht → Kunststoffkanüle vorschieben, Mandrin entfernen → Sicherung gegen Abknicken/Dislokation, sterile Abdeckung.",alternativen:["Keine bei vital bedrohlichem Spannungspneu"],erfolg:"Entweichen von Luft, Rückbildung Schocksymptomatik/Kreislaufinsuffizienz, Rückbildung Halsvenenstauung, verbesserte Atemmechanik/Oxygenierung",gegenmassnahmen:"Ggf. längere Kanüle bei Adipositas → 2. Punktion bei ausbleibendem Erfolg / erneuter Symptomatik (Abknickung/Verstopfung/Dislokation) → ggf. alternativer Punktionsort"},
{id:"defi",name:"Manuelle Defibrillation",indikationen:["Kammerflimmern (VF)","Pulslose ventrikuläre Tachykardie (pVT)"],kontra:["Alle EKG-Rhythmen außer VF und pVT (Asystolie, PEA)"],durchfuehrung:"Möglichst Klebeelektroden (Kinder: spez. Kinder-Klebeelektroden). Brustkorb sauber, trocken, haarfrei → Elektroden rechts-pectoral-apical oder anterior-posterior → Manuellen Modus anwählen → Rhythmusstörung identifizieren → Gerätespezifische Energie gemäß Herstellerangabe → Aufladen (HDM während Ladephase fortsetzen!) → Warnung → Schockabgabe → Sofort HDM fortsetzen → Weiter gemäß BPR Reanimation.",alternativen:["AED-Modus bei Unsicherheit"],erfolg:"ROSC, Terminierung VF/pVT",anmerkung:"Sicherheitsabstände zu sauerstoffführenden Gerätschaften beachten"},
{id:"kardioversion",name:"Kardioversion",indikationen:["Kardial bedingte Tachykardie mit hämodynamischer Instabilität und Bewusstlosigkeit"],kontra:["Fehlende Bewusstlosigkeit","Sinustachykardie"],durchfuehrung:"EKG-Ableitung über EKG-Elektroden → Brustkorb sauber, trocken, haarfrei → Elektroden rechts-pectoral-apical oder anterior-posterior → Rhythmusstörung identifizieren → AED-Funktion ggf. ausschalten → Synchronisierten Modus anwählen → Markierung QRS-Komplexe beachten → Erwachsene: 150 J → Aufladen → Warnung → Schockabgabe (ggf. kurze Verzögerung) → Rhythmus-/Pulskontrolle → Ggf. zweimalige Wiederholung → Ggf. CPR.",alternativen:["Medikamentöse Therapie durch NA"],erfolg:"Terminierung der Tachykardie, verbesserte Hämodynamik, Wiedererlangen des Bewusstseins",anmerkung:"Bei sehr breiten QRS ggf. keine Erkennung im Sync-Modus"},
{id:"schrittmacher",name:"Externe Schrittmacheranlage",indikationen:["Bradykardie mit hämodynamischer Instabilität und Bewusstlosigkeit"],kontra:["Technische Unmöglichkeit","Absolute Intoleranz durch Patient","Bewusstseinsklarer Patient mit klinischer Stabilität trotz Bradykardie"],durchfuehrung:"Brustkorb sauber, trocken, haarfrei → Inspektion auf implantiertem SM/ICD (Abstand!) → Elektroden anterior-posterior oder rechts-pectoral-apical → Möglichst Demand-Modus → Frequenz: 70/min → Stimulationsenergie: Start 25 mA → Zügige Steigerung um je 10 mA bis durchgehende Captures + tastbare Pulswelle → Nochmals +15 mA Sicherheitsüberschuss → Analgesie gemäß BPR Schmerzen.",alternativen:["Bei vital bedrohlicher Bradykardie ggf. CPR"],erfolg:"Sicheres Auslösen von Captures, Anstieg HF, tastbare Pulse analog Captures, verbesserte Hämodynamik/Neurologie, akzeptable Schmerzsituation",gegenmassnahmen:"Überprüfung/Wechsel Elektrodenposition bei ineffektiver Stimulation"},
{id:"tourniquet",name:"Tourniquet / Pneumatische Blutsperre",indikationen:["Lebensgefährliche Blutung / multiple Blutungsquellen an Extremität","Nichterreichbarkeit der Verletzung","Schwere Blutung bei gleichzeitigem kritischem A-/B-/C-Problem","Unmöglichkeit der Blutstillung durch andere Maßnahmen","Schwere Extremitätenblutung bei Zeitdruck/Gefahrensituationen"],kontra:["Blutstillung mit anderen Mitteln erreichbar","Absolute Intoleranz trotz adäquater Schmerztherapie"],durchfuehrung:"Anlage ca. 5-10 cm proximal der Blutungsquelle, gelenkfern → NICHT in Höhe Fibulaköpfchen (N. peronaeus!) → NICHT auf Kleidung (Lockerung/Verrutschen) → Knebel anziehen bis Blutstillung → Knebel fixieren → Blutfluss muss komplett gestoppt werden (sonst venöse Stauung!) → Uhrzeit notieren! → In der Regel keine Öffnung im RD → Ggf. Analgesie.",alternativen:["Abdrücken","Druckverband","Hämostyptika","Manuelle Kompression"],erfolg:"Sistieren der Blutung",gegenmassnahmen:"Analgesie → Bei Ineffektivität 2. Tourniquet oberhalb → Ggf. Druckverband/Kompression/Hämostyptika → Bei Unmöglichkeit: zeitkritischer Transport"},
{id:"beckenschlinge",name:"Beckenschlinge",indikationen:["Initiale Stabilisierung bei V.a. komplexe Beckenverletzungen (z.B. Beckenfraktur)"],kontra:["Technische Unmöglichkeit der Anlage","Absolute Intoleranz trotz adäquater Schmerztherapie"],durchfuehrung:"Anlage durch 2-3 Helfer gemäß Bedienungsanleitung → Fixierung der Beine (Knie), möglichst etwas innenrotiert → Kompression/Stabilisierung in Höhe Trochanter major beidseits → Kompression durch definierten Zug oder pneumatischen Druck → Anlagezeit dokumentieren → Bedarfsgerechte Analgesie. IMMER: Neurologische + Gefäßsituation prüfen/dokumentieren VOR und NACH Anlage. Regelmäßige Überprüfung. Keine Öffnung im RD.",alternativen:["Andere Stabilisierungsmöglichkeiten","Schneller Transport als Ultima ratio"],erfolg:"Sichere, feste Anlage, akzeptable Schmerzsituation",anmerkung:"Auch als Trochanterschlinge bezeichnet"},
{id:"cpap",name:"Nichtinvasives CPAP / NIV",indikationen:["Schwere respiratorische Partial- und Globalinsuffizienz","Kohlenmonoxid-Intoxikation"],kontra:["Bewusstloser oder unkooperativer Patient, Intoleranz der Maske","Fehlende Spontanatmung oder Schnappatmung","Spannungspneumothorax","Atemwegsverlegung, Erbrechen, akute GI-Blutung, Ileus","Gesichtsverletzung mit Blutung in Atemwegen, Frakturen, Deformitäten","Hämodynamische Instabilität / Schock / Hypotonie RRsyst < 90 mmHg"],durchfuehrung:"Patient ausführlich informieren (Compliance!) → AF, HF, RR, SpO₂ erfassen → Korrekte Maskengröße → Zunächst manuell halten (bessere Toleranz) → PEEP + PS je nach Krankheitsbild einstellen → Regelmäßig Beatmungsparameter kontrollieren → Maske mit Bändern fixieren → Abbruchkriterien beachten. Starteinstellungen: Hypoxie führend: FiO₂ 1,0 / PEEP 5 / PS 0 mbar → PEEP steigern. Hyperkapnie führend: FiO₂ 0,4-1,0 / PEEP 0 / PS 5 mbar → PS steigern. Mischform: FiO₂ 1,0 / PEEP 5 / PS 5 mbar. PEEP: 5-10 mbar nach SpO₂. PS: 5, 8, 12 mbar nach Tidalvolumen/etCO₂.",alternativen:["Hochdosierte O₂-Gabe (cave COPD)","Assistierte Beatmung über Beutel/Maske","Invasive Beatmung"],erfolg:"Verbesserung respiratorische Situation, SpO₂-Anstieg, AF-Reduktion, subjektive Besserung"},
{id:"achsengerecht",name:"Achsengerechte Immobilisation",indikationen:["Dislozierte Fraktur mit Gefahr weiterer Folgeschäden durch Fehlstellung / Durchblutungsstörung / Gewebespannung"],kontra:["Absolute Intoleranz durch Patient"],durchfuehrung:"Extension durch Zug am körperfernen (distalen) Frakturanteil → Achsengerechten Stand wiederherstellen → Gegensinnig zum Traumamechanismus: distal ziehen, proximal fixieren → Ggf. 2. Person zum Fixieren/Gegenhalten → Zügig, nicht unterbrochen durchführen → Konsequente Immobilisation unter Aufrechterhaltung der Extension → DMS prüfen + dokumentieren VOR und NACH Anlage → Regelmäßige Überprüfung. Besonderheiten: Schulter (Zurückhaltung, Fraktur möglich), Radius (Extension bei Fehlstellung), Hüfte (Vakuummatratze), Patella (Streckung → Repo), Sprunggelenk (unbedingt Extension bei Fehlstellung).",alternativen:["Bei fehlender Durchführbarkeit NA abwarten","Ggf. Analgosedierung/Kurznarkose/Relaxierung für Extension"],erfolg:"Achsengerechter Stand, Verbesserung DMS, akzeptable Schmerzsituation, verminderte Weichteilspannung"},
{id:"endobronchial",name:"Endobronchiales Absaugen",indikationen:["Akute respiratorische Insuffizienz durch symptomatische Verlegung der Atemwege durch Sekrete (Blut/Schleim/Eiter)"],kontra:["Keine"],durchfuehrung:"Präoxygenierung → Steriles Arbeiten unerlässlich (Händedesinfektion, sterile Handschuhe, sterile Absaugkatheter) → Monitoring (Cave Bradykardie bei Vagusreiz!) → Vorher Mund-/Rachen-/ggf. Nasenbereich absaugen → Sterilen Absaugkatheter OHNE Sog in Inspirationsphase tracheal einführen → Bei leichtem Widerstand ca. 1 cm zurückziehen → Häufig Hustenreiz = positive Reaktion → Mittels Fingertip Sog aufbauen, Katheter vorsichtig zurückziehen → Ggf. wiederholen mit neuem sterilem Katheter. Auch über Tracheostoma oder ETT möglich.",alternativen:["Verzicht bei ausreichender Oxygenierung und akzeptabler Atemmechanik"],erfolg:"Freie Atemwege ohne relevante Nebengeräusche, Beatmungsdruck prüfen",gegenmassnahmen:"Abbruch bei symptomatischer Reflexbradykardie (ggf. Atropin) → Abbruch bei reflektorischem Bronchospasmus"},
{id:"im_injektion",name:"Intramuskuläre Injektion",indikationen:["Epinephringabe bei anaphylaktischen Reaktionen","Glucagongabe bei Hypoglykämie","Opioidgabe zur Analgesie","Esketamingabe zur Analgesie","Midazolamgabe zur Krampfdurchbrechung"],kontra:["Kreislaufstillstand oder manifester Schock anderer Genese","Infektion oder eingeschränkte Durchblutung an Punktionsstelle","Paretische, verletzte oder (vor-)geschädigte Extremität","Therapie mit Antikoagulantien und Blutungsneigung"],durchfuehrung:"Punktionsstelle: mittleres Drittel lateraler Oberschenkel, ggf. Oberarm → Desinfektion → Haut spannen, Muskel nicht anspannen → Punktion senkrecht → Langsame Injektion (bei Widerstand/Knochen etwas zurückziehen) → Rasches Herausziehen + Kompression mit steriler Kompresse → Pflasterverband.",alternativen:["Buccale, rektale oder intranasale Gabe","Intravenös (angepasste Dosierung!)","Intraossär (angepasste Dosierung!)","Verzicht bis Eintreffen NA"],erfolg:"Keine Schwellung, keine Blutung, keine Dysästhesien, gewünschte pharmakologische Wirkung",anmerkung:"Kanülen: 18-22 G, Länge 25-70 mm"},
{id:"in_gabe",name:"Intranasale Medikamentengabe",indikationen:["Durchbrechung des Status epilepticus","Schmerzmedikation","Hypoglykämie (Glucagongabe)"],kontra:["Verletzung der Nase","Nasenbluten, übermäßige Schleimbildung"],durchfuehrung:"Höchstkonzentrierte Lösung, kleinstes Volumen wählen → Medikamentenvolumen in Spritze aufziehen → Zerstäuber (MAD) an Luer-Lock verbinden → Luft eliminieren → Hinterkopf des Patienten halten → Zerstäuber fest auf Nasenloch aufsetzen → Stempel nach oben und zur Seite ausrichten → Spritzenstempel zügig vorschieben → Max. 1 ml pro Nasenloch!",alternativen:["Buccale, rektale oder intramuskuläre Gabe","Intravenös","Intraossär","Verzicht bis Eintreffen NA"],erfolg:"Gewünschte pharmakologische Wirkung verabreichter Medikamente",anmerkung:"Spritzenaufsatz zur Zerstäubung (MAD-Nasal) erforderlich. Max. 1 ml pro Nasenloch."},
];
